import{_ as d,o as a,c as e,ai as r}from"./chunks/framework.ampVZV4B.js";const b=JSON.parse('{"title":"AI 热门软件与开源项目地图","description":"","frontmatter":{},"headers":[],"relativePath":"ai/explore/index.md","filePath":"ai/explore/index.md"}'),n={name:"ai/explore/index.md"};function h(o,t,i,l,s,g){return a(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="ai-热门软件与开源项目地图" tabindex="-1">AI 热门软件与开源项目地图 <a class="header-anchor" href="#ai-热门软件与开源项目地图" aria-label="Permalink to “AI 热门软件与开源项目地图”">​</a></h1><blockquote><p><strong>定位</strong>：用一张「分类地图」快速了解当下常见的 AI 应用、工具与开源项目——适合 <strong>选型参考、按需学习、面试闲聊素材</strong>，不等同于官方排行榜。<br><strong>和维护关系</strong>：仓库迭代快，请以各项目官网 / Release 为准；本文只描述<strong>典型用途</strong>与<strong>学习优先级</strong>。</p></blockquote><hr><h2 id="这张地图怎么读" tabindex="-1">这张地图怎么读？ <a class="header-anchor" href="#这张地图怎么读" aria-label="Permalink to “这张地图怎么读？”">​</a></h2><table tabindex="0"><thead><tr><th>你的目标</th><th>建议优先看</th></tr></thead><tbody><tr><td>先把大模型用顺、提效开发</td><td><a href="#一对话与编程辅助商用-开源">对话与编程辅助</a>、本地轻量 <a href="#二本地推理与管理终端侧体验">本地推理</a></td></tr><tr><td>做 Agent / 自动化工作流</td><td><a href="#三agent-工作流编排">Agent 与可视化编排</a>、<a href="#四rag-记忆-知识库">RAG 与知识库</a></td></tr><tr><td>自己部署模型、省 API 钱</td><td><a href="#五训练推理与服务化-gpu-工程向">推理与服务化</a>、<a href="/my-vitepress-site/ai/model-deploy/">部署专题</a></td></tr><tr><td>多模态 / AIGC 玩图与视频</td><td><a href="#六多模态与-aigc-管线">多模态与创意管线</a></td></tr><tr><td>了解「业界在造什么轮子」</td><td>全文扫一遍，把感兴趣的 <strong>Star + 读 README</strong></td></tr></tbody></table><hr><h2 id="一、对话与编程辅助-商用-开源" tabindex="-1">一、对话与编程辅助（商用 + 开源） <a class="header-anchor" href="#一、对话与编程辅助-商用-开源" aria-label="Permalink to “一、对话与编程辅助（商用 + 开源）”">​</a></h2><p>面向<strong>日常提问、写代码、改文档</strong>：闭源产品体验通常更省心；开源类适合<strong>自建、二次开发、学习协议与插件</strong>。</p><table tabindex="0"><thead><tr><th>名称</th><th>形态</th><th>适合谁</th><th>一句话</th><th>入口</th></tr></thead><tbody><tr><td>ChatGPT / Copilot（微软）</td><td>商用订阅</td><td>全栈、办公提效</td><td>生态全、插件多，适合「先习惯 AI 结对编程」</td><td>官网各产品线</td></tr><tr><td>Claude</td><td>商用 API / 网页</td><td>长文本、复杂推理</td><td>长上下文与说明书类任务口碑好</td><td>Anthropic</td></tr><tr><td>Cursor</td><td>商用 IDE</td><td>前端/全栈</td><td>「AI 原生编辑器」代表，适合重度编码</td><td>cursor.com</td></tr><tr><td>Continue</td><td>开源插件</td><td>想用 VS Code / JetBrains + 自建模型</td><td>可对接本地/Ollama/云端，适合练「工具链组装」</td><td>GitHub: continue-dev/continue</td></tr><tr><td>GitHub Copilot</td><td>商用</td><td>已在 Git GitHub 生态内</td><td>与 PR、Issue、Copilot Chat 一体</td><td>GitHub</td></tr><tr><td>通义灵码 / 豆包 / Kimi 等</td><td>国产商用</td><td>国内网络与合规</td><td>中文场景与文档检索往往更顺手</td><td>各厂商官网</td></tr></tbody></table><p><strong>学习建议</strong>：至少熟练 <strong>1 个闭源对话</strong> + <strong>1 个编辑器内助手</strong>；有折腾精神再装 <strong>Continue + 本地模型</strong>。</p><hr><h2 id="二、本地推理与管理-终端侧体验" tabindex="-1">二、本地推理与管理（终端侧体验） <a class="header-anchor" href="#二、本地推理与管理-终端侧体验" aria-label="Permalink to “二、本地推理与管理（终端侧体验）”">​</a></h2><p>在<strong>本机或内网</strong>跑小模型：隐私、离线、省 token；代价是机器配置与工程排错。</p><table tabindex="0"><thead><tr><th>名称</th><th>类型</th><th>适合谁</th><th>一句话</th><th>入口</th></tr></thead><tbody><tr><td>Ollama</td><td>本地模型拉起 + CLI</td><td>入门本地推理首选</td><td><code>pull / run</code> 一条龙，和 Continue、Dify 等常联动</td><td>ollama.com</td></tr><tr><td>llama.cpp</td><td>C/C++ 推理引擎</td><td>要极致压缩与嵌入式</td><td>各类「.gguf」与边缘部署常见底座</td><td>ggerganov/llama.cpp</td></tr><tr><td>LM Studio</td><td>桌面 GUI</td><td>不想敲命令</td><td>可视化下载与聊天，适合非研发体验</td><td>lmstudio.ai</td></tr><tr><td>llamafile</td><td>单文件分发</td><td>演示与传播</td><td>把权重+运行时打成一个文件，便于分享</td><td>Mozilla Ocho 系</td></tr><tr><td>GPT4All</td><td>桌面 + 本地 RAG</td><td>轻量知识库试验</td><td>自带简单文档检索玩法的入门套件</td><td>nomic-ai/gpt4all</td></tr></tbody></table><p>与站内 <a href="/my-vitepress-site/ai/model-deploy/">模型部署专题</a> 的关系：<strong>本表偏「客户端/工具」</strong>；<strong>vLLM、TGI</strong> 等偏服务端，见下一节。</p><hr><h2 id="三、agent-工作流编排" tabindex="-1">三、Agent / 工作流编排 <a class="header-anchor" href="#三、agent-工作流编排" aria-label="Permalink to “三、Agent / 工作流编排”">​</a></h2><p>让模型<strong>多步调用工具、走状态机、接业务 API</strong>：从库到产品的分水岭。</p><table tabindex="0"><thead><tr><th>名称</th><th>类型</th><th>适合谁</th><th>一句话</th><th>入口</th></tr></thead><tbody><tr><td>LangChain</td><td>Python/JS 生态框架</td><td>快速原型</td><td>组件多、示例多；需自己把控复杂度</td><td>langchain-ai/langchain</td></tr><tr><td>LangGraph</td><td>图状态机</td><td>要可控流程与重试</td><td>适合「多节点 Agent + 条件分支」</td><td>langchain-ai/langgraph</td></tr><tr><td>AutoGen / Semantic Kernel 等</td><td>多 Agent 协作</td><td>.NET / Python 团队</td><td>微软系与其它多角色对话实验</td><td>各官方仓库</td></tr><tr><td>Dify</td><td>开源 LLMOps 平台</td><td>低代码搭 Bot + 知识库</td><td>私有化、工作流、RAG 一套常有</td><td>langgenius/dify</td></tr><tr><td>FastGPT</td><td>开源应用编排</td><td>国内私有化常见</td><td>偏「应用 + 知识库」快速交付</td><td>labring/FastGPT</td></tr><tr><td>n8n</td><td>工作流自动化</td><td>运营 + 研发胶水</td><td>节点丰富，接 HTTP/Webhook，再挂 AI 节点即可</td><td>n8n-io/n8n</td></tr><tr><td>Coze / 扣子 等</td><td>平台型</td><td>快速验证</td><td>平台与开源「Bot 引擎」可对照学<strong>工作流建模</strong></td><td>各官方</td></tr></tbody></table><p><strong>学习建议</strong>：跟着本站 <a href="/my-vitepress-site/ai/stage-2-agent/">Agent 模块</a> 先写「<strong>单 Agent + 单工具</strong>」，再挑 <strong>Dify 或 LangGraph</strong> 二选一深入。</p><hr><h2 id="四、rag-记忆-知识库" tabindex="-1">四、RAG / 记忆 / 知识库 <a class="header-anchor" href="#四、rag-记忆-知识库" aria-label="Permalink to “四、RAG / 记忆 / 知识库”">​</a></h2><p>解决 <strong>「模型瞎编」与「读你的文档」</strong>：向量库、重排、索引管线是后端面试高频词。</p><table tabindex="0"><thead><tr><th>名称</th><th>类型</th><th>适合谁</th><th>一句话</th><th>入口</th></tr></thead><tbody><tr><td>LlamaIndex</td><td>Python 数据框架</td><td>做严肃 RAG</td><td>连接器与索引抽象全，适合与现有数据源对接</td><td>run-llama/llama_index</td></tr><tr><td>LangChain / LCEL</td><td>编排 + 向量存储抽象</td><td>已在 LC 生态</td><td>Retrieval Chain 模板多</td><td>同上 LangChain</td></tr><tr><td>Milvus / Qdrant / Weaviate 等</td><td>向量数据库</td><td>工程化部署</td><td>选型见业务规模与运维能力</td><td>各官方</td></tr><tr><td>AnythingLLM</td><td>本地知识库 GUI</td><td>想先要「能用的知识库」</td><td>文档拖入 + 对话，适合演示</td><td>Mintplex-Labs/anything-llm</td></tr><tr><td>Mem0</td><td>记忆层</td><td>多轮对话要「记住用户」</td><td>把记忆当组件接进 Agent</td><td>mem0ai/mem0</td></tr></tbody></table><hr><h2 id="五、训练、推理与服务化-gpu-工程向" tabindex="-1">五、训练、推理与服务化（GPU / 工程向） <a class="header-anchor" href="#五、训练、推理与服务化-gpu-工程向" aria-label="Permalink to “五、训练、推理与服务化（GPU / 工程向）”">​</a></h2><p>偏<strong>机房与云平台</strong>：与服务端 Java/Go/Python 同事协作时会遇到。</p><table tabindex="0"><thead><tr><th>名称</th><th>类型</th><th>适合谁</th><th>一句话</th><th>入口</th></tr></thead><tbody><tr><td>vLLM</td><td>高吞吐推理服务</td><td>生产 API</td><td>PagedAttention，适合多并发</td><td>vllm-project/vllm</td></tr><tr><td>Text Generation Inference (TGI)</td><td>Hugging Face 推理栈</td><td>HF 生态</td><td>与 HF 模型仓库衔接顺</td><td>huggingface/text-generation-inference</td></tr><tr><td>llama.cpp HTTP Server</td><td>轻量服务</td><td>小团队</td><td>资源占用相对可控</td><td>llama.cpp 子项目</td></tr><tr><td>Hugging Face Transformers / PEFT</td><td>训练与微调库</td><td>算法向</td><td>LoRA/QLoRA 等常见微调入口</td><td>huggingface</td></tr><tr><td>Axolotl / Unsloth</td><td>微调工具包</td><td>真要训小模型</td><td>封装训练配置，降低踩坑成本</td><td>各官方仓库</td></tr><tr><td>Open WebUI</td><td>自托管 Chat UI</td><td>内网统一入口</td><td>常和 Ollama 组合出现</td><td>open-webui/open-webui</td></tr></tbody></table><p>更系统的选型可对照：<a href="/my-vitepress-site/ai/model-deploy/04-runtime-compare.html">推理框架对比（2026）</a>。</p><hr><h2 id="六、多模态与-aigc-管线" tabindex="-1">六、多模态与 AIGC 管线 <a class="header-anchor" href="#六、多模态与-aigc-管线" aria-label="Permalink to “六、多模态与 AIGC 管线”">​</a></h2><p>文生图、图生图、工作流节点<strong>拖拽</strong>：视觉向与创意运营常用。</p><table tabindex="0"><thead><tr><th>名称</th><th>类型</th><th>适合谁</th><th>一句话</th><th>入口</th></tr></thead><tbody><tr><td>ComfyUI</td><td>节点式工作流</td><td>深度玩 SD 生态</td><td>可复现管线、社区节点极多</td><td>comfyanonymous/ComfyUI</td></tr><tr><td>Stable Diffusion WebUI (A1111)</td><td>Web 控制台</td><td>经典入门</td><td>插件多、资料多</td><td>AUTOMATIC1111/stable-diffusion-webui</td></tr><tr><td>InvokeAI</td><td>工具链</td><td>偏产品化体验</td><td>兼顾 CLI 与 UI</td><td>invoke-ai/InvokeAI</td></tr></tbody></table><hr><h2 id="七、评测、安全与可观测-进阶" tabindex="-1">七、评测、安全与可观测（进阶） <a class="header-anchor" href="#七、评测、安全与可观测-进阶" aria-label="Permalink to “七、评测、安全与可观测（进阶）”">​</a></h2><p>做产品或企业落地时，迟早要回答：<strong>「模型好不好」</strong>与<strong>「哪里会出事」</strong>。</p><table tabindex="0"><thead><tr><th>名称</th><th>类型</th><th>适合谁</th><th>一句话</th><th>入口</th></tr></thead><tbody><tr><td>OpenCompass 等</td><td>评测框架</td><td>要比榜单、比版本</td><td>统一跑基准，适合发版前回归</td><td>open-compass/opencompass</td></tr><tr><td>LangSmith / Phoenix 等</td><td>Trace / 调试</td><td>Agent 排障</td><td>看调用链、延迟与 Token</td><td>各云服务或开源</td></tr><tr><td>安全与红队工具（概念）</td><td>Policy / Guardrail</td><td>企业合规</td><td>输入输出过滤、提示注入防护需单独设计</td><td>按需检索最新项目</td></tr></tbody></table><hr><h2 id="使用本模块的姿势-防劝退" tabindex="-1">使用本模块的姿势（防劝退） <a class="header-anchor" href="#使用本模块的姿势-防劝退" aria-label="Permalink to “使用本模块的姿势（防劝退）”">​</a></h2><ol><li><strong>先选一个闭环</strong>：例如「Ollama + Open WebUI」或「Dify + 一份业务文档」，跑通比收藏重要。</li><li><strong>再和本站阶段路线对齐</strong>：<a href="/my-vitepress-site/ai/">/ai/</a> 里从 LLM → Agent → MVP Server 递进。</li><li><strong>每季度扫一眼 Release</strong>：热门项目的 breaking change 多，面试吹「我看过源码」前记得真的 clone 过一次。</li></ol><hr><h2 id="相关站内文档" tabindex="-1">相关站内文档 <a class="header-anchor" href="#相关站内文档" aria-label="Permalink to “相关站内文档”">​</a></h2><ul><li><a href="/my-vitepress-site/ai/">AI 探索总览</a></li><li><a href="/my-vitepress-site/ai/stage-2-agent/">Agent 循序渐进</a></li><li><a href="/my-vitepress-site/ai/model-deploy/">大模型部署及使用</a></li><li><a href="/my-vitepress-site/tech-system/ai/llm-basics.html">技术体系 · LLM 基础（长文地图）</a></li></ul>',43)])])}const c=d(n,[["render",h]]);export{b as __pageData,c as default};
